// ── LOGO injection ──────────────────────────────
const LOGO_B64 = "data:image/jpeg;base64,";
document.querySelectorAll('img[src="LOGO_SRC"]').forEach(img => img.src = LOGO_B64);

// ── ANNOUNCE BAR ─────────────────────────────────
function closeBar(){
  const bar = document.getElementById('announce-bar');
  bar.style.display = 'none';
  document.getElementById('main-nav').style.top = '0';
}
function updateNavTop(){
  const bar = document.getElementById('announce-bar');
  const nav = document.getElementById('main-nav');
  if(bar && bar.style.display !== 'none'){
    nav.style.top = bar.offsetHeight + 'px';
  } else {
    nav.style.top = '0';
  }
}
updateNavTop();
window.addEventListener('resize', updateNavTop);

// ── COUNTDOWN — target: Sep 1 2026 00:00:00 IST ──
const LAUNCH = new Date('2026-09-01T00:00:00+05:30').getTime();

function tick(){
  const now = Date.now();
  const diff = LAUNCH - now;
  if(diff <= 0){
    document.getElementById('countdown').innerHTML = '<span style="font-family:var(--f-orbitron);font-size:16px;font-weight:900;letter-spacing:2px">WE ARE LIVE 🎉</span>';
    return;
  }
  const days  = Math.floor(diff / 86400000);
  const hours = Math.floor((diff % 86400000) / 3600000);
  const mins  = Math.floor((diff % 3600000)  / 60000);
  const secs  = Math.floor((diff % 60000)    / 1000);
  document.getElementById('cd-d').textContent = String(days).padStart(2,'0');
  document.getElementById('cd-h').textContent = String(hours).padStart(2,'0');
  document.getElementById('cd-m').textContent = String(mins).padStart(2,'0');
  document.getElementById('cd-s').textContent = String(secs).padStart(2,'0');
}
tick();
setInterval(tick, 1000);

// ── FAQ accordion ─────────────────────────────────
document.querySelectorAll('.faq-q').forEach(btn => {
  btn.addEventListener('click', () => {
    const ans = btn.nextElementSibling;
    const wasOpen = btn.classList.contains('open');
    document.querySelectorAll('.faq-q').forEach(b => {
      b.classList.remove('open');
      b.nextElementSibling.classList.remove('visible');
    });
    if(!wasOpen){ btn.classList.add('open'); ans.classList.add('visible'); }
  });
});

// ── Waitlist claim — connected to Google Sheets backend ──
// !! PASTE YOUR APPS SCRIPT DEPLOYMENT URL BELOW !!
const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzGYv9f0HDN_Npc8e8950KsqC6S4UDa5hPFd4rloQaIw8DuoN7gqBAtzWy1mwzwT-Q/exec';
const SECRET_KEY      = 'unipair2026'; // must match Code.gs

async function claimSpot(btn) {
  // Gather values
  const nameEl   = document.getElementById('wl-name');
  const emailEl  = document.getElementById('wl-email');
  const campusEl = document.getElementById('wl-campus');
  const genderEl = document.getElementById('wl-gender');
  const msgEl    = document.getElementById('wl-msg');

  const name   = nameEl.value.trim();
  const email  = emailEl.value.trim();
  const campus = campusEl.value;
  const gender = genderEl.value;

  // Client-side validation
  if (!name)   { shake(nameEl);   showMsg(msgEl, 'Please enter your first name.', 'err'); return; }
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
                 shake(emailEl);  showMsg(msgEl, 'Please enter a valid college email.', 'err'); return; }
  if (!campus)  { shake(campusEl); showMsg(msgEl, 'Please select your campus.', 'err'); return; }
  if (!gender)  { shake(genderEl); showMsg(msgEl, 'Please select how you identify.', 'err'); return; }

  // Loading state
  btn.innerHTML = '⏳ Claiming your spot...';
  btn.disabled  = true;
  btn.style.background = '#666';
  showMsg(msgEl, '', '');

  try {
    // Use no-cors fetch — Apps Script doesn't send CORS headers on POST
    // So we use a callback/jsonp-style GET by encoding data in URL params,
    // OR we post to a hidden iframe. The most reliable cross-origin method
    // for Apps Script is fetch with no-cors (fire-and-forget) combined
    // with a separate GET to confirm.

    const payload = { name, email, campus, gender, key: SECRET_KEY };

    // Method: POST with no-cors (works, but response is opaque — we can't read it)
    // So we immediately also do a GET ping to verify the script is alive,
    // then assume success if the script URL is reachable.

    // Try readable POST first (works when opened via a server / file://)
    let data = null;
    try {
      const res = await fetch(APPS_SCRIPT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain' }, // text/plain avoids CORS preflight
        body: JSON.stringify(payload),
        redirect: 'follow',
      });
      const text = await res.text();
      // Apps Script redirects to a new URL after POST — parse the final response
      try { data = JSON.parse(text); } catch(e) { data = null; }
    } catch(fetchErr) {
      console.warn('Direct fetch blocked, trying no-cors fallback:', fetchErr.message);
    }

    // If direct fetch worked
    if (data && data.status === 'ok') {
      _handleSuccess(btn, name, msgEl, data.position);
      return;
    }
    if (data && data.status === 'duplicate') {
      _handleDuplicate(btn, msgEl);
      return;
    }

    // Fallback: no-cors POST (fire and forget) — cannot read response
    // but the data WILL be written to the sheet
    await fetch(APPS_SCRIPT_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain' },
      body: JSON.stringify(payload),
      mode: 'no-cors',
      redirect: 'follow',
    });

    // Since we can't read the no-cors response, verify by GET ping
    let verified = false;
    try {
      const ping = await fetch(APPS_SCRIPT_URL + '?ping=1', { mode: 'cors', redirect: 'follow' });
      const pingData = await ping.json();
      verified = pingData.status === 'alive';
    } catch(e) { verified = true; } // if even GET fails, script URL is wrong

    if (verified) {
      _handleSuccess(btn, name, msgEl, null);
    } else {
      throw new Error('Script URL unreachable — please check it in the HTML file.');
    }

  } catch (err) {
    btn.innerHTML        = 'CLAIM MY SPOT →';
    btn.style.background = 'var(--pink)';
    btn.style.boxShadow  = '';
    btn.disabled = false;
    showMsg(msgEl, '⚠ ' + (err.message || 'Could not connect. See troubleshooting guide.'), 'err');
    console.error('UniPair form error:', err);
  }
}

function _handleSuccess(btn, name, msgEl, position) {
  btn.innerHTML          = '🎉 YOU\'RE IN, ' + name.toUpperCase() + '!';
  btn.style.background   = '#0d7a40';
  btn.style.boxShadow    = '0 6px 30px rgba(13,122,64,0.35)';
  btn.disabled           = true;
  showMsg(msgEl, '✓ Spot claimed! We\'ll email you on launch day.', 'ok');
  const el = document.getElementById('wl-num');
  if (el && position) el.textContent = position.toLocaleString();
  confettiBurst();
}

function _handleDuplicate(btn, msgEl) {
  btn.innerHTML        = 'CLAIM MY SPOT →';
  btn.style.background = 'var(--pink)';
  btn.style.boxShadow  = '';
  btn.disabled         = false;
  showMsg(msgEl, '👀 This email is already on the waitlist!', 'warn');
}

function showMsg(el, text, type) {
  if (!el) return;
  el.textContent = text;
  el.style.color = type === 'ok' ? '#22dd6e' : type === 'warn' ? '#ffaa00' : '#ff6b6b';
}

function shake(el) {
  el.style.animation = 'none';
  el.offsetHeight; // reflow
  el.style.animation = 'shake 0.35s ease';
  el.addEventListener('animationend', () => el.style.animation = '', { once: true });
}

function confettiBurst() {
  const colors = ['#ff1a6b','#ffffff','#ff6b9e','#cc1555'];
  for (let i = 0; i < 60; i++) {
    const div = document.createElement('div');
    const size = Math.random() * 8 + 4;
    div.style.cssText = `position:fixed;width:${size}px;height:${size}px;
      background:${colors[i%colors.length]};border-radius:${Math.random()>0.5?'50%':'2px'};
      left:${Math.random()*100}vw;top:-10px;z-index:9999;pointer-events:none;
      animation:fall ${1.2+Math.random()*1.2}s ease forwards;`;
    document.body.appendChild(div);
    setTimeout(() => div.remove(), 2800);
  }
}